# Validate
with open(output_path, 'r', encoding='utf-8') as f:
    lines = f.readlines()
    for i, line in enumerate(lines, 1):
        try:
            obj = json.loads(line)
            assert 'instruction' in obj and 'input' in obj and 'output' in obj, f"Missing field on line {i}"
            assert '<user>' in obj['output'], f"No <user> tag on line {i}"
        except json.JSONDecodeError as e:
            print(f"INVALID JSON on line {i}: {e}")
        except AssertionError as e:
            print(f"VALIDATION ERROR: {e}")
    print(f"Validated {len(lines)} lines, all OK")
